@dataclass
class Document:
    content: str
    metadata: Dict = field(default_factory=dict)
    doc_id: Optional[str] = None

    def __post_init__(self):
        if self.doc_id is None:
            self.doc_id = hashlib.sha256(self.content.encode('utf-8')).hexdigest()[:16]


@dataclass
class RetrievedDocument:
    content: str
    metadata: Dict
    score: float
    doc_id: str


class InputSanitizer:
    """Sanitizes user inputs to prevent injection attacks."""

    PROMPT_INJECTION_PATTERNS = [
        r"ignore\s+(all\s+)?previous\s+instructions",
        r"disregard\s+(all\s+)?previous",
        r"forget\s+(all\s+)?previous",
        r"you\s+are\s+now\s+in\s+developer\s+mode",
        r"system\s*:\s*",
        r"<\|.*?\|>",
        r"\[INST\]",
        r"\[/INST\]",
        r"<<SYS>>",
        r"<</SYS>>",
    ]

    @classmethod
    def sanitize_query(cls, query: str, max_length: int = 2000) -> str:
        if not isinstance(query, str):
            raise ValueError("Query must be a string")

        query = query.strip()

        if not query:
            raise ValueError("Query cannot be empty")

        if len(query) > max_length:
            query = query[:max_length]
            logger.warning("Query truncated to %d characters", max_length)

        # Check for prompt injection patterns
        for pattern in cls.PROMPT_INJECTION_PATTERNS:
            if re.search(pattern, query, re.IGNORECASE):
                logger.warning("Potential prompt injection detected and blocked: pattern=%s", pattern)
                raise ValueError("Query contains disallowed patterns")

        # Remove control characters except newlines and tabs
        query = ''.join(
            char for char in query
            if char in ('\n', '\t') or (ord(char) >= 32)
        )

        return query

    @classmethod
    def sanitize_document_content(cls, content: str, max_length: int = 100000) -> str:
        if not isinstance(content, str):
            raise ValueError("Document content must be a string")

        content = content.strip()

        if not content:
            raise ValueError("Document content cannot be empty")

        if len(content) > max_length:
            content = content[:max_length]
            logger.warning("Document content truncated to %d characters", max_length)

        return content

    @classmethod
    def sanitize_file_path(cls, file_path: str, allowed_base_dirs: List[str]) -> Path:
        """Validate and sanitize file paths to prevent path traversal attacks."""
        path = Path(file_path).resolve()

        # Check for path traversal
        is_allowed = False
        for base_dir in allowed_base_dirs:
            base = Path(base_dir).resolve()
            try:
                path.relative_to(base)
                is_allowed = True
                break
            except ValueError:
                continue

        if not is_allowed:
            raise ValueError(f"File path '{file_path}' is outside allowed directories")

        if not path.exists():
            raise FileNotFoundError(f"File not found: {path}")

        if not path.is_file():
            raise ValueError(f"Path is not a file: {path}")

        return path


class TextChunker:
    """Splits documents into chunks for embedding."""

    def __init__(self, chunk_size: int = 500, chunk_overlap: int = 50):
        if chunk_size <= 0:
            raise ValueError("chunk_size must be positive")
        if chunk_overlap < 0:
            raise ValueError("chunk_overlap must be non-negative")
        if chunk_overlap >= chunk_size:
            raise ValueError("chunk_overlap must be less than chunk_size")

        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap

    def chunk_text(self, text: str) -> List[str]:
        """Split text into overlapping chunks by sentences."""
        sentences = re.split(r'(?<=[.!?])\s+', text)
        chunks = []
        current_chunk = []
        current_length = 0

        for sentence in sentences:
            sentence_length = len(sentence)

            if current_length + sentence_length > self.chunk_size and current_chunk:
                chunk_text = ' '.join(current_chunk)
                chunks.append(chunk_text)

                # Keep overlap
                overlap_chunk = []
                overlap_length = 0
                for s in reversed(current_chunk):
                    if overlap_length + len(s) <= self.chunk_overlap:
                        overlap_chunk.insert(0, s)
                        overlap_length += len(s)
                    else:
                        break

                current_chunk = overlap_chunk
                current_length = overlap_length

            current_chunk.append(sentence)
            current_length += sentence_length

        if current_chunk:
            chunks.append(' '.join(current_chunk))

        return chunks


class EmbeddingModel:
    """Wrapper around sentence-transformers for generating embeddings."""

    def __init__(self, model_name: str = "all-MiniLM-L6-v2"):
        logger.info("Loading embedding model: %s", model_name)
        self.model = SentenceTransformer(model_name)
        self.model_name = model_name

    def embed(self, texts: List[str]) -> List[List[float]]:
        if not texts:
            return []
        embeddings = self.model.encode(texts, show_progress_bar=False)
        return embeddings.tolist()

    def embed_single(self, text: str) -> List[float]:
        return self.embed([text])[0]


class VectorStore:
    """ChromaDB-based vector store for document storage and retrieval."""

    def __init__(
        self,
        collection_name: str = "knowledge_base",
        persist_directory: Optional[str] = None,
        embedding_model: Optional[EmbeddingModel] = None,
    ):
        self.embedding_model = embedding_model or EmbeddingModel()

        # Sanitize collection name
        collection_name = re.sub(r'[^a-zA-Z0-9_-]', '_', collection_name)

        if persist_directory:
            persist_path = Path(persist_directory).resolve()
            persist_path.mkdir(parents=True, exist_ok=True)
            self.client = chromadb.PersistentClient(
                path=str(persist_path),
                settings=Settings(
                    anonymized_telemetry=False,
                    allow_reset=False,
                )
            )
        else:
            self.client = chromadb.Client(
                settings=Settings(
                    anonymized_telemetry=False,
                    allow_reset=False,
                )
            )

        self.collection = self.client.get_or_create_collection(
            name=collection_name,
            metadata={"hnsw:space": "cosine"}
        )

        logger.info(
            "Vector store initialized: collection=%s, documents=%d",
            collection_name,
            self.collection.count()
        )

    def add_documents(self, documents: List[Document]) -> int:
        """Add documents to the vector store. Returns number of documents added."""
        if not documents:
            return 0

        ids = []
        contents = []
        metadatas = []

        for doc in documents:
            ids.append(doc.doc_id)
            contents.append(doc.content)
            # Ensure metadata values are strings, ints, floats, or bools (ChromaDB requirement)
            sanitized_metadata = {}
            for k, v in doc.metadata.items():
                if isinstance(v, (str, int, float, bool)):
                    sanitized_metadata[k] = v
                else:
                    sanitized_metadata[k] = str(v)
            metadatas.append(sanitized_metadata)

        embeddings = self.embedding_model.embed(contents)

        # Add in batches to avoid memory issues
        batch_size = 100
        added = 0
        for i in range(0, len(ids), batch_size):
            batch_end = min(i + batch_size, len(ids))
            self.collection.upsert(
                ids=ids[i:batch_end],
                embeddings=embeddings[i:batch_end],
                documents=contents[i:batch_end],
                metadatas=metadatas[i:batch_end],
            )
            added += batch_end - i

        logger.info("Added %d documents to vector store", added)
        return added

    def query(self, query_text: str, n_results: int = 5) -> List[RetrievedDocument]:
        """Query the vector store and return relevant documents."""
        if self.collection.count() == 0:
            logger.warning("Vector store is empty")
            return []

        n_results = min(n_results, self.collection.count())

        query_embedding = self.embedding_model.embed_single(query_text)

        results = self.collection.query(
            query_embeddings=[query_embedding],
            n_results=n_results,
            include=["documents", "metadatas", "distances"]
        )

        retrieved_docs = []
        if results and results['documents'] and results['documents'][0]:
            for i, doc_content in enumerate(results['documents'][0]):
                # ChromaDB returns distances; convert to similarity score
                distance = results['distances'][0][i] if results['distances'] else 0.0
                score = 1.0 - distance  # cosine distance to similarity

                retrieved_docs.append(RetrievedDocument(
                    content=doc_content,
                    metadata=results['metadatas'][0][i] if results['metadatas'] else {},
                    score=score,
                    doc_id=results['ids'][0][i] if results['ids'] else "",
                ))

        return retrieved_docs

    def get_document_count(self) -> int:
        return self.collection.count()


class DocumentLoader:
    """Loads documents from files and directories."""

    ALLOWED_EXTENSIONS = {'.txt', '.md', '.json', '.csv', '.py', '.html', '.xml', '.yaml', '.yml', '.log', '.rst'}
    MAX_FILE_SIZE_BYTES = 10 * 1024 * 1024  # 10 MB

    def __init__(self, allowed_base_dirs: List[str], chunker: Optional[TextChunker] = None):
        self.allowed_base_dirs = [str(Path(d).resolve()) for d in allowed_base_dirs]
        self.chunker = chunker or TextChunker()

    def load_file(self, file_path: str) -> List[Document]:
        """Load a single file and return chunked documents."""
        safe_path = InputSanitizer.sanitize_file_path(file_path, self.allowed_base_dirs)

        if safe_path.suffix.lower() not in self.ALLOWED_EXTENSIONS:
            raise ValueError(f"File type not allowed: {safe_path.suffix}")

        file_size = safe_path.stat().st_size
        if file_size > self.MAX_FILE_SIZE_BYTES:
            raise ValueError(
                f"File too large: {file_size} bytes (max: {self.MAX_FILE_SIZE_BYTES})"
            )

        try:
            content = safe_path.read_text(encoding='utf-8')
        except UnicodeDecodeError:
            logger.error("Cannot read file as UTF-8: %s", safe_path)
            raise ValueError(f"File is not valid UTF-8: {safe_path}")

        content = InputSanitizer.sanitize_document_content(content)
        chunks = self.chunker.chunk_text(content)

        documents = []
        for i, chunk in enumerate(chunks):
            doc = Document(
                content=chunk,
                metadata={
                    "source": safe_path.name,
                    "source_path": str(safe_path),
                    "chunk_index": i,
                    "total_chunks": len(chunks),
                    "file_type": safe_path.suffix.lower(),
                }
            )
            documents.append(doc)

        logger.info("Loaded file %s: %d chunks", safe_path.name, len(documents))
        return documents

    def load_directory(self, directory_path: str, recursive: bool = True) -> List[Document]:
        """Load all supported files from a directory."""
        dir_path = Path(directory_path).resolve()

        # Validate directory is within allowed base dirs
        is_allowed = False
        for base_dir in self.allowed_base_dirs:
            try:
                dir_path.relative_to(Path(base_dir).resolve())
                is_allowed = True
                break
            except ValueError:
                continue

        if not is_allowed:
            raise ValueError(f"Directory '{directory_path}' is outside allowed directories")

        if not dir_path.is_dir():
            raise ValueError(f"Not a directory: {dir_path}")

        all_documents = []
        glob_pattern = '**/*' if recursive else '*'

        for file_path in dir_path.glob(glob_pattern):
            if file_path.is_file() and file_path.suffix.lower() in self.ALLOWED_EXTENSIONS:
                try:
                    docs = self.load_file(str(file_path))
                    all_documents.extend(docs)
                except (ValueError, FileNotFoundError) as e:
                    logger.warning("Skipping file %s: %s", file_path, e)

        logger.info("Loaded directory %s: %d total chunks from files", dir_path, len(all_documents))
        return all_documents


class LLMClient:
    """Secure wrapper around OpenAI API for LLM interactions."""

    def __init__(
        self,
        api_key: Optional[str] = None,
        model: str = "gpt-3.5-turbo",
        base_url: Optional[str] = None,
        max_tokens: int = 1024,
        temperature: float = 0.1,
    ):
        resolved_api_key = api_key or os.environ.get("OPENAI_API_KEY")
        if not resolved_api_key:
            raise ValueError(
                "OpenAI API key must be provided via parameter or OPENAI_API_KEY environment variable"
            )

        client_kwargs = {"api_key": resolved_api_key}
        if base_url:
            client_kwargs["base_url"] = base_url

        self.client = OpenAI(**client_kwargs)
        self.model = model
        self.max_tokens = max_tokens
        self.temperature = temperature

    def generate(self, system_prompt: str, user_message: str) -> str:
        """Generate a response from the LLM."""
        try:
            response = self.client.chat.completions.create(
                model=self.model,
                messages=[
                    {"role": "system", "content": system_prompt},
                    {"role": "user", "content": user_message},
                ],
                max_tokens=self.max_tokens,
                temperature=self.temperature,
            )
            return response.choices[0].message.content.strip()
        except Exception as e:
            logger.error("LLM API call failed: %s", str(e))
            raise


class RAGSystem:
    """Main RAG system that ties together retrieval and generation."""

    SYSTEM_PROMPT = """You are a helpful internal knowledge base assistant. Your role is to answer questions based ONLY on the provided context documents.

Rules:
1. Only use information from the provided context documents to answer questions.
2. If the context does not contain enough information to answer the question, say so clearly.
3. Do not make up information or use knowledge outside of the provided context.
4. Cite the source document when possible.
5. Be concise and accurate in your responses.
6. If the question is unclear, ask for clarification."""

    def __init__(
        self,
        vector_store: Optional[VectorStore] = None,
        llm_client: Optional[LLMClient] = None,
        document_loader: Optional[DocumentLoader] = None,
        n_results: int = 5,
        min_relevance_score: float = 0.3,
    ):
        self.vector_store = vector_store
        self.llm_client = llm_client
        self.document_loader = document_loader
        self.n_results = n_results
        self.min_relevance_score = min_relevance_score

    def ingest_file(self, file_path: str) -> int:
        """Ingest a single file into the knowledge base."""
        if not self.document_loader:
            raise RuntimeError("Document loader not configured")

        documents = self.document_loader.load_file(file_path)
        return self.vector_store.add_documents(documents)

    def ingest_directory(self, directory_path: str, recursive: bool = True) -> int:
        """Ingest all files from a directory into the knowledge base."""
        if not self.document_loader:
            raise RuntimeError("Document loader not configured")

        documents = self.document_loader.load_directory(directory_path, recursive=recursive)
        return self.vector_store.add_documents(documents)

    def ingest_text(self, text: str, metadata: Optional[Dict] = None) -> int:
        """Ingest raw text into the knowledge base."""
        text = InputSanitizer.sanitize_document_content(text)
        chunker = TextChunker()
        chunks = chunker.chunk_text(text)

        documents = []
        for i, chunk in enumerate(chunks):
            doc_metadata = metadata.copy() if metadata else {}
            doc_metadata["chunk_index"] = i
            doc_metadata["total_chunks"] = len(chunks)
            doc_metadata["source"] = doc_metadata.get("source", "direct_input")

            documents.append(Document(content=chunk, metadata=doc_metadata))

        return self.vector_store.add_documents(documents)

    def _build_context(self, retrieved_docs: List[RetrievedDocument]) -> str:
        """Build context string from retrieved documents."""
        if not retrieved_docs:
            return "No relevant documents found."

        context_parts = []
        for i, doc in enumerate(retrieved_docs, 1):
            source = doc.metadata.get("source", "Unknown")
            chunk_info = ""
            if "chunk_index" in doc.metadata and "total_chunks" in doc.metadata:
                chunk_info = f" (chunk {doc.metadata['chunk_index'] + 1}/{doc.metadata['total_chunks']})"

            context_parts.append(
                f"--- Document {i} [Source: {source}{chunk_info}] (Relevance: {doc.score:.2f}) ---\n"
                f"{doc.content}\n"
            )

        return "\n".join(context_parts)

    def _build_user_message(self, query: str, context: str) -> str:
        """Build the user message with context and query."""
        return (
            f"Context Documents:\n"
            f"{context}\n\n"
            f"---\n\n"
            f"Question: {query}\n\n"
            f"Please answer the question based only on the context documents provided above."
        )

    def query(self, user_query: str) -> Dict:
        """Process a user query through the RAG pipeline."""
        # Sanitize input
        sanitized_query = InputSanitizer.sanitize_query(user_query)

        # Retrieve relevant documents
        retrieved_docs = self.vector_store.query(
            query_text=sanitized_query,
            n_results=self.n_results,
        )

        # Filter by minimum relevance score
        filtered_docs = [
            doc for doc in retrieved_docs
            if doc.score >= self.min_relevance_score
        ]

        if not filtered_docs:
            logger.info("No documents met the relevance threshold for query: %s", sanitized_query[:100])

        # Build context from ALL retrieved (and filtered) documents
        context = self._build_context(filtered_docs)

        # Build prompt and generate response
        user_message = self._build_user_message(sanitized_query, context)

        if self.llm_client:
            answer = self.llm_client.generate(
                system_prompt=self.SYSTEM_PROMPT,
                user_message=user_message,
            )
        else:
            answer = (
                "LLM client not configured. Here are the retrieved documents:\n\n"
                f"{context}"
            )

        # Build response with metadata
        response = {
            "query": sanitized_query,
            "answer": answer,
            "sources": [
                {
                    "content": doc.content[:200] + "..." if len(doc.content) > 200 else doc.content,
                    "source": doc.metadata.get("source", "Unknown"),
                    "relevance_score": round(doc.score, 4),
                    "doc_id": doc.doc_id,
                }
                for doc in filtered_docs
            ],
            "num_documents_retrieved": len(filtered_docs),
            "total_documents_in_store": self.vector_store.get_document_count(),
        }

        return response

    def interactive_chat(self):
        """Run an interactive chat session."""
        print("\n" + "=" * 60)
        print("  Internal Knowledge Base Chatbot")
        print(f"  Documents in knowledge base: {self.vector_store.get_document_count()}")
        print("  Type 'quit' or 'exit' to end the session")
        print("  Type 'stats' to see knowledge base statistics")
        print("=" * 60 + "\n")

        while True:
            try:
                user_input = input("\nYou: ").strip()
            except (EOFError, KeyboardInterrupt):
                print("\nGoodbye!")
                break

            if not user_input:
                continue

            if user_input.lower() in ('quit', 'exit'):
                print("Goodbye!")
                break

            if user_input.lower() == 'stats':
                print(f"\nKnowledge base contains {self.vector_store.get_document_count()} document chunks.")
                continue

            try:
                result = self.query(user_input)

                print(f"\nAssistant: {result['answer']}")

                if result['sources']:
                    print(f"\n  📚 Sources ({result['num_documents_retrieved']} documents):")
                    for src in result['sources']:
                        print(f"    - {src['source']} (relevance: {src['relevance_score']:.2f})")

            except ValueError as e:
                print(f"\n⚠️  Invalid input: {e}")
            except Exception as e:
                logger.error("Error processing query: %s", str(e))
                print(f"\n❌ An error occurred: {e}")


def create_rag_system(
    documents_dir: Optional[str] = None,
    persist_directory: str = "./chroma_db",
    openai_api_key: Optional[str] = None,
    openai_model: str = "gpt-3.5-turbo",
    openai_base_url: Optional[str] = None,
    collection_name: str = "knowledge_base",
    chunk_size: int = 500,
    chunk_overlap: int = 50,
    n_results: int = 5,
    min_relevance_score: float = 0.3,
    allowed_base_dirs: Optional[List[str]] = None,
) -> RAGSystem:
    """Factory function to create a fully configured RAG system."""

    # Set up allowed directories
    if allowed_base_dirs is None:
        allowed_base_dirs = []
    if documents_dir:
        allowed_base_dirs.append(documents_dir)
    if not allowed_base_dirs:
        allowed_base_dirs = [os.getcwd()]

    # Initialize components
    embedding_model = EmbeddingModel()

    vector_store = VectorStore(
        collection_name=collection_name,
        persist_directory=persist_directory,
        embedding_model=embedding_model,
    )

    chunker = TextChunker(chunk_size=chunk_size, chunk_overlap=chunk_overlap)

    document_loader = DocumentLoader(
        allowed_base_dirs=allowed_base_dirs,
        chunker=chunker,
    )

    # Initialize LLM client (optional - works without it for retrieval-only mode)
    llm_client = None
    api_key = openai_api_key or os.environ.get("OPENAI_API_KEY")
    if api_key:
        try:
            llm_client = LLMClient(
                api_key=api_key,
                model=openai_model,
                base_url=openai_base_url,
            )
            logger.info("LLM client initialized with model: %s", openai_model)
        except Exception as e:
            logger.warning("Failed to initialize LLM client: %s. Running in retrieval-only mode.", e)
    else:
        logger.warning("No OpenAI API key found. Running in retrieval-only mode.")

    rag = RAGSystem(
        vector_store=vector_store,
        llm_client=llm_client,
        document_loader=document_loader,
        n_results=n_results,
        min_relevance_score=min_relevance_score,
    )

    # Ingest documents if directory provided
    if documents_dir and Path(documents_dir).is_dir():
        logger.info("Ingesting documents from: %s", documents_dir)
        count = rag.ingest_directory(documents_dir)
        logger.info("Ingested %d document chunks", count)

    return rag


