    if args.query:
        # Single query mode
        result = rag_system.query(args.query)
        print(f"\nAnswer: {result['answer']}")
        print(f"\nSources ({result['num_documents_retrieved']}):")
        for src in result['sources']:
            print(f"  - {src['source']} (relevance: {src['relevance_score']:.2f})")
    else:
        # Interactive mode
        rag_system.interactive_chat()